class Solution:
    def findValidSplit(self, nums):
        import math
        n = len(nums)
        total = 1
        for v in nums:
            total *= v
        prefix = 1
        for i in range(n - 1):
            prefix *= nums[i]
            suffix = total // prefix
            if math.gcd(prefix, suffix) == 1:
                return i
        return -1

