class Solution:
    def findValidSplit(self, nums):
        n = len(nums)
        MAXV = 10 ** 6 + 1
        spf = list(range(MAXV))
        i = 2
        while i * i < MAXV:
            if spf[i] == i:
                for j in range(i * i, MAXV, i):
                    if spf[j] == j:
                        spf[j] = i
            i += 1
        first = {}
        last = {}
        for idx, v in enumerate(nums):
            x = v
            while x > 1:
                p = spf[x]
                if p not in first:
                    first[p] = idx
                last[p] = idx
                while x % p == 0:
                    x //= p
        diff = [0] * (n + 1)
        for p in first:
            lo, hi = first[p], last[p]
            if lo < hi:
                diff[lo] += 1
                diff[hi] -= 1
        cover = 0
        for i in range(n - 1):
            cover += diff[i]
            if cover == 0:
                return i
        return -1

