var findValidSplit = function(nums) {
    const n = nums.length;
    const MAXV = 1000001;
    const spf = new Int32Array(MAXV);
    for (let i = 0; i < MAXV; i++) spf[i] = i;
    for (let i = 2; i * i < MAXV; i++) {
        if (spf[i] === i) {
            for (let j = i * i; j < MAXV; j += i) {
                if (spf[j] === j) spf[j] = i;
            }
        }
    }
    const first = new Map();
    const last = new Map();
    for (let idx = 0; idx < n; idx++) {
        let x = nums[idx];
        while (x > 1) {
            const p = spf[x];
            if (!first.has(p)) first.set(p, idx);
            last.set(p, idx);
            while (x % p === 0) x = Math.floor(x / p);
        }
    }
    const diff = new Array(n + 1).fill(0);
    for (const [p, lo] of first) {
        const hi = last.get(p);
        if (lo < hi) {
            diff[lo] += 1;
            diff[hi] -= 1;
        }
    }
    let cover = 0;
    for (let i = 0; i < n - 1; i++) {
        cover += diff[i];
        if (cover === 0) return i;
    }
    return -1;
};
